    font-size: var(--font-base);
    color: var(--text-primary);
    word-break: break-word;
}

/* 删除按钮 */
.btn-delete {
    width: 32px;
    height: 32px;
    border-radius: var(--radius-md);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--text-disabled);
