.btn-delete:hover {
    background: var(--danger-color);
    color: white;
}

/* 空状态 */
.empty-state {
    display: none;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: var(--spacing-2xl);
    text-align: center;
}

.empty-state.show {
    display: flex;
