    .filter-section {
        flex-direction: column;
        align-items: stretch;
    }

    .filter-buttons {
        justify-content: center;
    }

    .btn-clear {
        width: 100%;
    }

    .todo-item {
        padding: var(--spacing-md);
    }
}
