    constructor() {
        // 获取DOM元素
        this.todoInput = document.getElementById('todoInput');
        this.addBtn = document.getElementById('addBtn');
        this.todoList = document.getElementById('todoList');
        this.emptyState = document.getElementById('emptyState');
        this.filterBtns = document.querySelectorAll('.filter-btn');
        this.clearBtn = document.getElementById('clearCompleted');
        this.countAll = document.getElementById('countAll');
        this.countActive = document.getElementById('countActive');
        this.countCompleted = document.getElementById('countCompleted');
        this.remainingCount = document.getElementById('remainingCount');

        this.currentFilter = 'all';
    }

    /**
     * 获取输入框的值
     */
    getInputValue() {
        return this.todoInput.value;
    }

    /**
     * 清空输入框
     */
    clearInput() {
        this.todoInput.value = '';
        this.todoInput.focus();
    }

    /**
     * 渲染任务列表
     */
    renderTodos(todos) {
        this.todoList.innerHTML = '';

        if (todos.length === 0) {
            this.showEmptyState();
        } else {
            this.hideEmptyState();
            todos.forEach(todo => {
                this.todoList.appendChild(this.createTodoElement(todo));
            });
        }
    }

    /**
     * 创建单个任务元素
     */
    createTodoElement(todo) {
        const li = document.createElement('li');
        li.className = `todo-item ${todo.completed ? 'completed' : ''}`;
        li.dataset.id = todo.id;

        li.innerHTML = `
            <div class="todo-checkbox ${todo.completed ? 'checked' : ''}"></div>
            <span class="todo-text">${this.escapeHtml(todo.text)}</span>
            <button class="btn-delete" title="删除任务">
                <svg width="20" height="20" viewBox="0 0 20 20" fill="currentColor">
