AssistantMessage(role='assistant', content=[TextContent(type='text', text='您说得对！我现在立即创建JavaScript文件。让我创建模块化的JS文件：', text_signature=None), ToolCall(type='toolCall', id='call_cc6275679c8a461f9654c747', name='write', arguments={'path': 'TODOLIST/js/todoModel.js', 'content': "/**
 * TodoModel - 数据模型层
 * 负责任务数据的存储、获取和管理
 */
class TodoModel {
    constructor() {
        this.storageKey = 'todos';
        this.todos = this.loadTodos();
    }

    /**
     * 从本地存储加载任务
     */
    loadTodos() {
        try {
            const stored = localStorage.getItem(this.storageKey);
            return stored ? JSON.parse(stored) : [];
        } catch (error) {
            console.error('加载任务失败:', error);
            return [];
        }
    }

    /**
     * 保存任务到本地存储
     */
    saveTodos() {
        try {
            localStorage.setItem(this.storageKey, JSON.stringify(this.todos));
        } catch (error) {
            console.error('保存任务失败:', error);
        }
    }

    /**
     * 获取所有任务
     */
    getTodos() {
        return this.todos;
    }

    /**
     * 根据状态获取任务
     */
    getTodosByStatus(status) {
        switch (status) {
            case 'active':
                return this.todos.filter(todo => !todo.completed);
            case 'completed':
                return this.todos.filter(todo => todo.completed);
            default:
                return this.todos;
        }
    }

    /**
     * 添加新任务
     */
    addTodo(text) {
        const newTodo = {
            id: Date.now(),
            text: text.trim(),
            completed: false,
            createdAt: new Date().toISOString()
        };
        this.todos.unshift(newTodo);
        this.saveTodos();
        return newTodo;
    }

    /**
     * 切换任务完成状态
     */
    toggleTodo(id) {
        const todo = this.todos.find(t => t.id === id);
        if (todo) {
            todo.completed = !todo.completed;
            this.saveTodos();
            return todo;
        }
        return null;
    }

    /**
     * 删除任务
     */
    deleteTodo(id) {
        const index = this.todos.findIndex(t => t.id === id);
        if (index !== -1) {
            const deleted = this.todos.splice(index, 1)[0];
            this.saveTodos();
            return deleted;
        }
        return null;
    }

    /**
     * 清除所有已完成的任务
     */
    clearCompleted() {
        const beforeLength = this.todos.length;
        this.todos = this.todos.filter(todo => !todo.completed);
        const clearedCount = beforeLength - this.todos.length;
        this.saveTodos();
        return clearedCount;
    }

    /**
     * 获取统计信息
     */
    getStats() {
        const total = this.todos.length;
        const completed = this.todos.filter(t => t.completed).length;
        const active = total - completed;

        return {
            total,
            completed,
            active
        };
    }

    /**
     * 更新任务文本
     */
    updateTodoText(id, newText) {
        const todo = this.todos.find(t => t.id === id);
        if (todo && newText.trim()) {
            todo.text = newText.trim();
            this.saveTodos();
            return todo;
        }
        return null;
    }
}
