 * TodoView - 视图层
 * 负责UI的渲染和DOM操作
 */
class TodoView {
    constructor() {
        // 获取DOM元素
        this.todoInput = document.getElementById('todoInput');
        this.addBtn = document.getElementById('addBtn');
        this.todoList = document.getElementById('todoList');
        this.emptyState = document.getElementById('emptyState');
        this.filterBtns = document.querySelectorAll('.filter-btn');
        this.clearBtn = document.getElementById('clearCompleted');
        this.countAll = document.getElementById('countAll');
        this.countActive = document.getElementById('countActive');
        this.countCompleted = document.getElementById('countCompleted');
        this.remainingCount = document.getElementById('remainingCount');

        this.currentFilter = 'all';
    }

    /**
     * 获取输入框的值
     */
    getInputValue() {
        return this.todoInput.value;
    }

    /**
     * 清空输入框
     */
    clearInput() {
        this.todoInput.value = '';
        this.todoInput.focus();
    }

    /**
     * 渲染任务列表
     */
    renderTodos(todos) {
        this.todoList.innerHTML = '';

        if (todos.length === 0) {
            this.showEmptyState();
        } else {
            this.hideEmptyState();
            todos.forEach(todo => {
                this.todoList.appendChild(this.createTodoElement(todo));
            });
        }
    }

    /**
     * 创建单个任务元素
     */
    createTodoElement(todo) {
        const li = document.createElement('li');
        li.className = `todo-item ${todo.completed ? 'completed' : ''}`;
        li.dataset.id = todo.id;

        li.innerHTML = `
            <div class="todo-checkbox ${todo.completed ? 'checked' : ''}"></div>
            <span class="todo-text">${this.escapeHtml(todo.text)}</span>
            <button class="btn-delete" title="删除任务">
                <svg width="20" height="20" viewBox="0 0 20 20" fill="currentColor">
                    <path fill-rule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clip-rule="evenodd"/>
                </svg>
            </button>
        `;

        return li;
    }

    /**
     * 更新统计信息
     */
    updateStats(stats) {
        this.countAll.textContent = stats.total;
        this.countActive.textContent = stats.active;
        this.countCompleted.textContent = stats.completed;
        this.remainingCount.textContent = stats.active;
    }

    /**
     * 更新过滤器状态
     */
    updateFilter(filter) {
        this.currentFilter = filter;
        this.filterBtns.forEach(btn => {
            if (btn.dataset.filter === filter) {
                btn.classList.add('active');
            } else {
                btn.classList.remove('active');
            }
        });
    }

    /**
     * 显示空状态
     */
    showEmptyState() {
        this.emptyState.classList.add('show');
    }

    /**
     * 隐藏空状态
     */
    hideEmptyState() {
        this.emptyState.classList.remove('show');
    }

    /**
     * HTML转义，防止XSS攻击
     */
    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    /**
     * 显示添加动画
     */
    animateAdd(element) {
        element.style.animation = 'slideIn 0.3s ease-out';
    }

    /**
